class PipelineStage:
    def __init__(self, name, cpu_latency_ns, fpga_latency_ns, 
                 cpu_cost=0, fpga_cost=0, parallel_with=None):
        self.name = name
        self.cpu_latency_ns = cpu_latency_ns
        self.fpga_latency_ns = fpga_latency_ns
        self.cpu_cost = cpu_cost
        self.fpga_cost = fpga_cost
        self.parallel_with = parallel_with


class LatencyAnalyzer:
    def __init__(self):
        self.stages = [
            PipelineStage('nic_receive', 10, 10, cpu_cost=1, fpga_cost=1),
            PipelineStage('protocol_parse', 1500, 25, cpu_cost=2, fpga_cost=8),
            PipelineStage('book_update', 3000, 35, cpu_cost=2, fpga_cost=10),
            PipelineStage('signal_gen', 2000, 45, cpu_cost=3, fpga_cost=15),
            PipelineStage('risk_check', 500, 20, cpu_cost=2, fpga_cost=6, 
                         parallel_with='order_format'),
            PipelineStage('order_format', 300, 50, cpu_cost=1, fpga_cost=5),
            PipelineStage('nic_transmit', 100, 100, cpu_cost=1, fpga_cost=1),
        ]
        self.stage_names = [s.name for s in self.stages]

    def get_stage_latency(self, stage, hw):
        if hw == 'fpga':
            return stage.fpga_latency_ns
        return stage.cpu_latency_ns

    def compute_latency(self, assignment):
        total = 0
        skip_stages = set()

        for stage in self.stages:
            if stage.name in skip_stages:
                continue

            latency = self.get_stage_latency(stage, assignment[stage.name])

            if stage.parallel_with:
                # Find the parallel stage
                parallel_stage = None
                for s in self.stages:
                    if s.name == stage.parallel_with:
                        parallel_stage = s
                        break
                if parallel_stage:
                    parallel_latency = self.get_stage_latency(
                        parallel_stage, assignment[parallel_stage.name]
                    )
                    total += max(latency, parallel_latency)
                    skip_stages.add(parallel_stage.name)
                else:
                    total += latency
            else:
                total += latency

        return total

    def compute_cost(self, assignment):
        total = 0
        for stage in self.stages:
            if assignment[stage.name] == 'fpga':
                total += stage.fpga_cost
            else:
                total += stage.cpu_cost
        return total

    def critical_path(self, assignment):
        path = []
        skip_stages = set()

        for stage in self.stages:
            if stage.name in skip_stages:
                continue

            if stage.parallel_with:
                parallel_stage = None
                for s in self.stages:
                    if s.name == stage.parallel_with:
                        parallel_stage = s
                        break
                if parallel_stage:
                    lat_a = self.get_stage_latency(stage, assignment[stage.name])
                    lat_b = self.get_stage_latency(parallel_stage, assignment[parallel_stage.name])
                    if lat_a >= lat_b:
                        path.append(stage.name)
                    else:
                        path.append(parallel_stage.name)
                    skip_stages.add(parallel_stage.name)
                else:
                    path.append(stage.name)
            else:
                path.append(stage.name)

        return path

    def optimize(self, max_cost):
        n = len(self.stages)
        best_latency = float('inf')
        best_assignment = None
        best_cost = 0

        all_cpu = {s.name: 'cpu' for s in self.stages}
        cpu_baseline = self.compute_latency(all_cpu)

        # Try all 2^n assignments
        for mask in range(1 << n):
            assignment = {}
            for i, stage in enumerate(self.stages):
                if mask & (1 << i):
                    assignment[stage.name] = 'fpga'
                else:
                    assignment[stage.name] = 'cpu'

            cost = self.compute_cost(assignment)
            if cost > max_cost:
                continue

            latency = self.compute_latency(assignment)
            if latency < best_latency:
                best_latency = latency
                best_assignment = assignment
                best_cost = cost

        if best_assignment is None:
            best_assignment = all_cpu
            best_latency = cpu_baseline
            best_cost = self.compute_cost(all_cpu)

        return {
            'assignment': best_assignment,
            'latency': best_latency,
            'cost': best_cost,
            'speedup_vs_cpu': cpu_baseline / best_latency if best_latency > 0 else 0
        }

    def analyze(self, max_cost):
        all_cpu = {s.name: 'cpu' for s in self.stages}
        all_fpga = {s.name: 'fpga' for s in self.stages}

        cpu_latency = self.compute_latency(all_cpu)
        fpga_latency = self.compute_latency(all_fpga)
        optimal = self.optimize(max_cost)

        return {
            'all_cpu_latency_ns': cpu_latency,
            'all_fpga_latency_ns': fpga_latency,
            'optimal': optimal,
            'critical_path': self.critical_path(optimal['assignment']),
            'per_stage': [
                {
                    'name': s.name,
                    'hw': optimal['assignment'][s.name],
                    'latency_ns': self.get_stage_latency(
                        s, optimal['assignment'][s.name]
                    ),
                    'cpu_latency_ns': s.cpu_latency_ns,
                    'fpga_latency_ns': s.fpga_latency_ns,
                    'savings_ns': s.cpu_latency_ns - self.get_stage_latency(
                        s, optimal['assignment'][s.name]
                    ),
                }
                for s in self.stages
            ]
        }

analyzer = LatencyAnalyzer()
max_budget = 30

result = analyzer.analyze(max_budget)
print(f"All-CPU latency: {result['all_cpu_latency_ns']} ns")
print(f"All-FPGA latency: {result['all_fpga_latency_ns']} ns")
print(f"Optimal latency: {result['optimal']['latency']} ns (cost: {result['optimal']['cost']})")
print(f"Speedup vs CPU: {result['optimal']['speedup_vs_cpu']:.1f}x")
print(f"Critical path: {result['critical_path']}")
print("\nPer-stage breakdown:")
for s in result['per_stage']:
    print(f"  {s['name']:20s}: {s['hw']:4s} -> {s['latency_ns']:6d} ns (saved {s['savings_ns']} ns)")
